            aWandererC = aWandererC ^ ((RotL64(aIngress, 6U) + aOrbiterF) + RotL64(aOrbiterE, 53U));
            aWandererJ = aWandererJ + ((RotL64(aCross, 11U) + RotL64(aOrbiterA, 35U)) + aOrbiterH);
            aWandererB = aWandererB ^ (((RotL64(aIngress, 41U) + RotL64(aOrbiterB, 43U)) + aOrbiterC) + aPhaseFWandererUpdateSaltB[((aIndex + 6U)) & S_SALT1]);
