            aOrbiterJ = ((aWandererC + RotL64(aPrevious, 35U)) + RotL64(aCarry, 19U)) + 0x9BD3FAD771A69457ULL;
            aOrbiterE = (aWandererB + RotL64(aScatter, 52U)) + 0x34FC974680B1E13AULL;
            aOrbiterB = ((aWandererD + RotL64(aPrevious, 41U)) + 0xA963C43E76180CA6ULL) + aPhaseAOrbiterAssignSaltE[((aIndex + 11U)) & S_SALT1];
