            aOrbiterC = ((aOrbiterC + aOrbiterJ) + 0x09306A378E398F4EULL) + aPhaseAOrbiterUpdateSaltB[(((31U - aIndex) + 17U)) & S_SALT1];
            aOrbiterF = ((aOrbiterF ^ aOrbiterC) ^ 0xDAB234E2686A0254ULL) ^ aPhaseAOrbiterUpdateSaltD[((aIndex + 22U)) & S_SALT1];
            aOrbiterF = RotL64((aOrbiterF * 0x5397C1020BA742F9ULL), 43U);
            //
            aOrbiterE = (aOrbiterE + aOrbiterG) + 0x1F767967C247D921ULL;
            aOrbiterB = (aOrbiterB ^ aOrbiterE) ^ 0x3B078E4139BE2F68ULL;
            aOrbiterB = RotL64((aOrbiterB * 0xE949856361EE596BULL), 51U);
            //
            aOrbiterB = ((aOrbiterB + aOrbiterH) + 0x474A8F882695EC12ULL) + aPhaseAOrbiterUpdateSaltC[((aIndex + 3U)) & S_SALT1];
            aOrbiterD = ((aOrbiterD ^ aOrbiterB) ^ 0x158B090174AADAC3ULL) ^ aPhaseAOrbiterUpdateSaltA[(((31U - aIndex) + 27U)) & S_SALT1];
            aOrbiterD = RotL64((aOrbiterD * 0x762C292C5A79B511ULL), 27U);
            //
            aOrbiterJ = (aOrbiterJ + aOrbiterD) + 0x47135385E6E91E86ULL;
            aOrbiterE = (aOrbiterE ^ aOrbiterJ) ^ 0x283848CC34E12BCBULL;
